import clsx from "clsx";

/**
 * Single flow: STEP LABEL → TITLE → SUBTITLE → (optional actions) → HERO IMAGE
 * No duplicate title blocks across breakpoints.
 */
export function StepHero({
  stepLabel,
  title,
  subtitle,
  imageSrc,
  imageAlt,
  className,
  /** When false, only the hero image renders (rare; prefer using full hero). */
  showMobileMeta = true,
  /** Plan page: taller image (h-52) instead of aspect-[16/6]. */
  planHero = false,
  /** e.g. Share button, aligned top-right next to title block on md+. */
  trailing = null,
}) {
  return (
    <div className={clsx("space-y-4", className)}>
      {showMobileMeta ? (
        <div className="space-y-1">
          <p className="text-xs font-semibold uppercase tracking-wide text-blue-600">{stepLabel}</p>
          <div className="flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
            <div>
              <h1 className="text-2xl font-semibold text-gray-900">{title}</h1>
              <p className="mt-1 text-sm text-gray-500">{subtitle}</p>
            </div>
            {trailing ? <div className="shrink-0 sm:pt-0.5">{trailing}</div> : null}
          </div>
        </div>
      ) : null}

      <div
        className={clsx(
          "w-full overflow-hidden rounded-xl border border-gray-200 shadow-sm mb-6",
          planHero ? "h-52" : "aspect-[16/6]"
        )}
      >
        <img
          src={imageSrc}
          alt={imageAlt}
          className="h-full w-full object-cover"
          loading="lazy"
        />
      </div>
    </div>
  );
}
